#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>

#define MAX_ARGS 10
#define REC_LENGTH 49	// size of a record in db
#define REC_WINDOW 10	// number of records to read at a time
#define LATITUDE_POS 28	// location of latitude coordinates in input record
#define OPEN 10000	// initial value of nearest neighbors
#define BLOCK_SIZE 256

struct neighbor {
	char entry[REC_LENGTH];
	double dist;
};

// Helper function to convert a string to float on the device
__device__ float device_atof(const char* str) {
    float result = 0.0;
    int sign = 1;
    int decimal_point_seen = 0;
    float fraction = 0.1;

    if (*str == '-') {
        sign = -1;
        str++;
    }

    while (*str) {
        if (*str >= '0' && *str <= '9') {
            if (decimal_point_seen) {
                result += (*str - '0') * fraction;
                fraction *= 0.1;
            } else {
                result = result * 10.0 + (*str - '0');
            }
        } else if (*str == '.') {
            decimal_point_seen = 1;
        } else {
            // Handle potential non-numeric characters if necessary,
            // for this problem, we assume valid float strings.
            break;
        }
        str++;
    }
    return sign * result;
}


__global__ void calculate_distances(const char* sandbox, int rec_count, float target_lat, float target_long, float* z) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < rec_count) {
        const char* rec_iter = sandbox + (idx * REC_LENGTH);
        // Assuming latitude is at the beginning of the string and longitude is 5 chars after it.
        // This is a simplification based on the original atof usage.
        // A more robust solution would parse the string more carefully.
        float tmp_lat = device_atof(rec_iter);
        float tmp_long = device_atof(rec_iter + 5); // Assuming longitude is 5 chars after latitude
        z[idx] = sqrt(((tmp_lat - target_lat) * (tmp_lat - target_lat)) + ((tmp_long - target_long) * (tmp_long - target_long)));
    }
}

int main(int argc, char* argv[]) {
	long long time0 = clock();
    FILE   *flist,*fp;
	int    i=0,j=0, k=0, rec_count=0, done=0;
	char   sandbox[REC_LENGTH * REC_WINDOW], dbname[64];
	struct neighbor *neighbors = NULL;
	float target_lat, target_long;

	if(argc < 5) {
		fprintf(stderr, "Invalid set of arguments\n");
		exit(-1);
	}

	flist = fopen(argv[1], "r");
	if(!flist) {
		printf("error opening flist\n");
		exit(1);
	}

	k = atoi(argv[2]);
	target_lat = atof(argv[3]);
	target_long = atof(argv[4]);

	neighbors = (struct neighbor*) malloc(k*sizeof(struct neighbor));

	if(neighbors == NULL) {
		fprintf(stderr, "no room for neighbors\n");
		exit(0);
	}

	for( j = 0 ; j < k ; j++ ) { //Initialize list of nearest neighbors to very large dist
		neighbors[j].dist = OPEN;
	}

	/**** main processing ****/
	if(fscanf(flist, "%s\n", dbname) != 1) {
		fprintf(stderr, "error reading filelist\n");
		exit(0);
	}

	fp = fopen(dbname, "r");
	if(!fp) {
		printf("error opening flist\n");
		exit(1);
	}

	char *d_sandbox;
	float *d_z;
	float *z_host = (float *) malloc(REC_WINDOW * sizeof(float));

	if (z_host == NULL) {
		fprintf(stderr, "no room for z_host\n");
		exit(0);
	}

	cudaMalloc(&d_sandbox, REC_LENGTH * REC_WINDOW);
	cudaMalloc(&d_z, REC_WINDOW * sizeof(float));

	while(!done) {
		rec_count = fread(sandbox, REC_LENGTH, REC_WINDOW, fp);
		if( rec_count != REC_WINDOW ) {
			if(!ferror(flist)) {
				fclose(fp);
				if(feof(flist))
		  			done = 1;
				else {
	 				if(fscanf(flist, "%s\n", dbname) != 1) {
	    					fprintf(stderr, "error reading filelist\n");
	    					exit(0);
					}
	  				fp = fopen(dbname, "r");
	  				if(!fp) {
					    printf("error opening a db\n");
					    exit(1);
	  				}
				}
			} else {
				perror("Error");
				exit(0);
			}
		}

		if (rec_count > 0) {
			cudaMemcpy(d_sandbox, sandbox, REC_LENGTH * rec_count, cudaMemcpyHostToDevice);

			dim3 gridDim((rec_count + BLOCK_SIZE - 1) / BLOCK_SIZE);
			dim3 blockDim(BLOCK_SIZE);
			calculate_distances<<<gridDim, blockDim>>>(d_sandbox, rec_count, target_lat, target_long, d_z);
			cudaDeviceSynchronize();
			cudaError_t err = cudaGetLastError();
			if (err != cudaSuccess) {
				fprintf(stderr, "CUDA error: %s\n", cudaGetErrorString(err));
				exit(1);
			}

			cudaMemcpy(z_host, d_z, sizeof(float) * rec_count, cudaMemcpyDeviceToHost);

			for( i = 0 ; i < rec_count ; i++ ) {
				float max_dist = -1;
				int max_idx = 0;
				for( j = 0 ; j < k ; j++ ) {
					if( neighbors[j].dist > max_dist ) {
						max_dist = neighbors[j].dist;
						max_idx = j;
					}
				}
				if( z_host[i] < neighbors[max_idx].dist ) {
					// Ensure null termination before strcpy
					sandbox[(i+1)*REC_LENGTH-1] = '\0';
				  	strcpy(neighbors[max_idx].entry, sandbox +i*REC_LENGTH);
				  	neighbors[max_idx].dist = z_host[i];
				}
			}
		}
	}

	fprintf(stderr, "The %d nearest neighbors are:\n", k);
	for( j = 0 ; j < k ; j++ ) {
		if( !(neighbors[j].dist == OPEN) )
			fprintf(stderr, "%s --> %f\n", neighbors[j].entry, neighbors[j].dist);
	}

	fclose(flist);
	cudaFree(d_sandbox);
	cudaFree(d_z);
	free(z_host);

    long long time1 = clock();
    printf("total time : %15.12f s", (float) (time1 - time0) / 1000000);
    return 0;
}
